export const topicBySlug = Object.fromEntries(topics.map(t => [t.slug, t]));

export const topicsByCategory = topics.reduce((acc, t) => {
  if (!acc[t.category]) acc[t.category] = [];
  acc[t.category].push(t);
  return acc;
}, {} as Record<string, Topic[]>);
